    op: Union[str, None] = None  # for operators
    left: Union['ASTNode', None] = None  # for binop
    right: Union['ASTNode', None] = None  # for binop
    operand: Union['ASTNode', None] = None  # for unary


def parse(expression: str) -> ASTNode:
    """Parse a mathematical expression string into an AST"""
    expression = expression.strip()
    if not expression:
        raise ValueError("Empty expression")

    tokens = _tokenize(expression)
    if not tokens:
        raise ValueError("No tokens found in expression")

    parser = _ExpressionParser(tokens)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    """Evaluate an AST to a numeric result"""
    if node.type == 'number':
        return node.value
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")
    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")


class _ExpressionParser:
    """Helper class for parsing expressions with proper precedence"""

    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def parse(self):
        """Parse the expression starting with the lowest precedence"""
        return self._parse_expression()

    def _parse_expression(self):
        """Parse addition and subtraction (lowest precedence)"""
        node = self._parse_term()

        while self._current() in ('+', '-'):
            op = self._current()
            self._advance()
            right = self._parse_term()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_term(self):
        """Parse multiplication and division (medium precedence)"""
        node = self._parse_factor()

        while self._current() in ('*', '/'):
            op = self._current()
            self._advance()
            right = self._parse_factor()
            node = ASTNode(type='binop', op=op, left=node, right=right)

        return node

    def _parse_factor(self):
        """Parse numbers, unary operators, and parenthesized expressions (highest precedence)"""
        token = self._current()

        if token == '-':
            self._advance()
            operand = self._parse_factor()
            return ASTNode(type='unary', op='-', operand=operand)
        elif token == '(':
            self._advance()
            node = self._parse_expression()
            if self._current() != ')':
                raise ValueError("Unmatched parentheses")
            self._advance()
            return node
        elif self._is_number(token):
            value = float(token)
            self._advance()
            return ASTNode(type='number', value=value)
        else:
            raise ValueError(f"Unexpected token: {token}")

    def _current(self):
        """Get the current token or None if at end"""
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def _advance(self):
        """Move to the next token"""
        if self.pos < len(self.tokens):
            self.pos += 1

    def _is_number(self, token):
        """Check if token is a valid number"""
        try:
            float(token)
            return True
        except ValueError:
            return False


